<template>
  <div>
    <el-breadcrumb separator="/" style="padding-left: 10px;padding-bottom: 10px;font-size: 12px">
      <el-breadcrumb-item :to="{ path: '/main' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>系统管理</el-breadcrumb-item>
      <el-breadcrumb-item>学生简历信息查看</el-breadcrumb-item>
    </el-breadcrumb>

    <el-card class="box-card">
      <el-form :inline="true" :model="dataVo" class="demo-form-inline">
        <el-form-item label="简历名称" label-width="70px">
          <el-input clearable v-model="dataVo.rtitle" placeholder="请输入简历名称"></el-input>
        </el-form-item>
        <el-form-item label="岗位名称" label-width="70px">
          <el-input clearable v-model="dataVo.rwantworks" placeholder="请输入岗位名称"></el-input>
        </el-form-item>
        <el-form-item label="学生姓名" label-width="70px">
          <el-input clearable v-model="dataVo.sname" placeholder="请输入学生姓名"></el-input>
        </el-form-item>
        <el-form-item label="学生电话" label-width="70px">
          <el-input clearable v-model="dataVo.stel" placeholder="请输入学生电话"></el-input>
        </el-form-item>
        <el-form-item label="专业名称" label-width="70px">
          <el-input clearable v-model="dataVo.smajor" placeholder="请输入专业名称"></el-input>
        </el-form-item>
        <el-form-item label="学院名称" label-width="70px">
          <el-input clearable v-model="dataVo.scollege" placeholder="请输入学院名称"></el-input>
        </el-form-item>
        <el-form-item label="班级名称" label-width="70px">
          <el-input clearable v-model="dataVo.sclass" placeholder="请输入班级名称"></el-input>
        </el-form-item>
        <el-form-item label="简历类型" label-width="70px">
          <el-input clearable v-model="dataVo.tname" placeholder="请输入简历类型"></el-input>
        </el-form-item>
        <el-form-item style="margin-left: 10px">
          <el-button icon="el-icon-refresh" @click="resetDataVo">重置</el-button>
          <el-button type="primary" icon="el-icon-search" @click="getDataList">查询</el-button>
        </el-form-item>
      </el-form>
      <el-table
        :data="dataList"
        border
        max-height="400"
        style="width: 100%;">
        <el-table-column
          prop="id"
          label="#"
          type="index"
          width="50">
        </el-table-column>
        <el-table-column
          prop="rtitle"
          label="简历名称"
          width="120">
        </el-table-column>
        <el-table-column
          prop="rwages"
          label="期望薪资"
          width="80">
        </el-table-column>
        <el-table-column
          sortable
          prop="rdate"
          label="添加日期"
          width="100">
          <template slot-scope="scope">
            {{scope.row.rdate}}
          </template>
        </el-table-column>
        <el-table-column
          prop="sname"
          label="学生姓名"
          width="80">
        </el-table-column>
        <el-table-column
          prop="stel"
          label="学生电话"
          width="150">
        </el-table-column>
        <el-table-column
          prop="smajor"
          label="专业名称"
          width="120">
        </el-table-column>
        <el-table-column
          prop="scollege"
          label="学院名称"
          width="120">
        </el-table-column>
        <el-table-column
          prop="sclass"
          label="班级名称"
          width="120">
        </el-table-column>
        <el-table-column
          prop="tname"
          label="简历类型"
          width="120">
        </el-table-column>
        <el-table-column
          sortable
          prop="rwantworks"
          label="期望工作"
          width="180">
        </el-table-column>
        <el-table-column
          prop="rworks"
          label="工作经历"
          width="280">
        </el-table-column>
        <el-table-column
          prop="redus"
          label="教育经历"
          width="280">
        </el-table-column>
      </el-table>
      <el-pagination
        style="padding-top: 15px"
        @size-change="handleSizeChange"
        @current-change="handleCurrentChange"
        :current-page="current"
        :page-sizes="[6, 10, 20, 30]"
        :page-size="size"
        layout="total, sizes, prev, pager, next, jumper"
        :total="total">
      </el-pagination>
    </el-card>
  </div>

</template>

<script>
  import { findCompanyresumesDatasList,deleteDatas } from '../../api/resumes';

  export default {
    name: 'Resumes',
    data() {
      return {
        dataVo: {
          rtitle:'',
          rwantworks:'',
          smajor: '',
          sname: '',
          stel: '',
          scollege: '',
          sclass: '',
          tname:''
        },
        addOrUpdateVisible: false,
        editOrUpdateVisible: false,
        dataList: [],
        size: 6,
        total: 100,
        current: 1
      };
    },
    components: {
    },
    created(){
      this.getDataList();
    },
    methods: {
      onSubmit() {
      },
      handleSizeChange(val) {
        this.size = val;
        this.getDataList();
      },
      handleCurrentChange(val) {
        this.current = val;
        this.getDataList();
      },
      async getDataList(){
        const { data } = await findCompanyresumesDatasList(this.current,this.size,this.dataVo);
        this.dataList = data.data.records;
        this.total = data.data.total;
      },
      resetDataVo(){
        this.dataVo.smajor = '';
        this.dataVo.sname = '';
        this.dataVo.rtitle = '';
        this.dataVo.stel= '';
        this.dataVo.rwantworks= '';
        this.dataVo.scollege= '';
        this.dataVo.sclass= '';
        this.dataVo.tname= '';
        this.getDataList();
      },
      show(){
        this.addOrUpdateVisible = true;
      },
       dataEdit(row){
        var that = this;
         this.editOrUpdateVisible = true;
        this.$nextTick(() => {
            that.$refs.eidtOrUpdateRef.dataInit(row);
        });
         this.getDataList();
        console.log(this.dataEdit);
      },
      showAddOrUpdate(data){
        if(data === 'false'){
          this.addOrUpdateVisible = false;
        }else{
          this.addOrUpdateVisible = true;
        }
        this.getDataList();
      },
      showEidtOrUpdate(data){
        if(data === 'false'){
          this.editOrUpdateVisible = false;
        }else{
          this.editOrUpdateVisible = true;
        }
        this.getDataList();
      }
    }
  };
</script>

<style scoped>

</style>
